exercises.instructions:
Implement two functions:

1. `encode_instruction(mnemonic: str, args: dict) -> int` — Given an instruction mnemonic (e.g., 'ADD', 'ADDI', 'LW', 'BEQ', 'JAL', 'LUI') and a dictionary of arguments, return the 32-bit encoded instruction as an integer.

Argument dictionaries vary by format:
- R-type: {'rd': int, 'rs1': int, 'rs2': int}
- I-type: {'rd': int, 'rs1': int, 'imm': int}
- S-type: {'rs1': int, 'rs2': int, 'imm': int}
- B-type: {'rs1': int, 'rs2': int, 'imm': int}
- U-type: {'rd': int, 'imm': int}
- J-type: {'rd': int, 'imm': int}

2. `decode_instruction(instruction: int) -> dict` — Given a 32-bit instruction integer, return a dictionary with keys 'mnemonic', 'format', and the relevant fields (rd, rs1, rs2, imm) with the immediate sign-extended to a Python int.

You must support these instructions:
- R-type: ADD, SUB, AND, OR, XOR, SLT, SLL, SRL, SRA
- I-type arithmetic: ADDI, ANDI, ORI, XORI, SLTI
- I-type load: LW
- I-type jump: JALR
- S-type: SW
- B-type: BEQ, BNE, BLT, BGE
- U-type: LUI, AUIPC
- J-type: JAL

Immediates for B-type and J-type must be in multiples of 2 (bit 0 is always 0 and not stored).

exercises.solutionCode:
from typing import Dict, Union

R_TYPE_OPCODE = 0b0110011
I_ARITH_OPCODE = 0b0010011
LOAD_OPCODE = 0b0000011
STORE_OPCODE = 0b0100011
BRANCH_OPCODE = 0b1100011
JAL_OPCODE = 0b1101111
JALR_OPCODE = 0b1100111
LUI_OPCODE = 0b0110111
AUIPC_OPCODE = 0b0010111

R_FUNCT = {
    'ADD': (0b0000000, 0b000), 'SUB': (0b0100000, 0b000),
    'SLL': (0b0000000, 0b001), 'SLT': (0b0000000, 0b010),
    'XOR': (0b0000000, 0b100), 'SRL': (0b0000000, 0b101),
    'SRA': (0b0100000, 0b101), 'OR':  (0b0000000, 0b110),
    'AND': (0b0000000, 0b111),
}

I_FUNCT3 = {
    'ADDI': 0b000, 'SLTI': 0b010, 'XORI': 0b100,
    'ORI': 0b110, 'ANDI': 0b111,
}

B_FUNCT3 = {
    'BEQ': 0b000, 'BNE': 0b001, 'BLT': 0b100, 'BGE': 0b101,
}


def _sign_extend(value: int, bits: int) -> int:
    """Sign-extend a value from 'bits' width to Python int."""
    sign_bit = 1 << (bits - 1)
    return (value ^ sign_bit) - sign_bit


def _mask(value: int, bits: int) -> int:
    """Mask value to the given number of bits."""
    return value & ((1 << bits) - 1)


def encode_instruction(mnemonic: str, args: Dict[str, int]) -> int:
    """Encode a RISC-V instruction into a 32-bit integer."""
    mnemonic = mnemonic.upper()

    if mnemonic in R_FUNCT:
        funct7, funct3 = R_FUNCT[mnemonic]
        rd = args['rd'] & 0x1F
        rs1 = args['rs1'] & 0x1F
        rs2 = args['rs2'] & 0x1F
        return (funct7 << 25) | (rs2 << 20) | (rs1 << 15) | (funct3 << 12) | (rd << 7) | R_TYPE_OPCODE

    elif mnemonic in I_FUNCT3:
        funct3 = I_FUNCT3[mnemonic]
        rd = args['rd'] & 0x1F
        rs1 = args['rs1'] & 0x1F
        imm = _mask(args['imm'], 12)
        return (imm << 20) | (rs1 << 15) | (funct3 << 12) | (rd << 7) | I_ARITH_OPCODE

    elif mnemonic == 'LW':
        rd = args['rd'] & 0x1F
        rs1 = args['rs1'] & 0x1F
        imm = _mask(args['imm'], 12)
        return (imm << 20) | (rs1 << 15) | (0b010 << 12) | (rd << 7) | LOAD_OPCODE

    elif mnemonic == 'JALR':
        rd = args['rd'] & 0x1F
        rs1 = args['rs1'] & 0x1F
        imm = _mask(args['imm'], 12)
        return (imm << 20) | (rs1 << 15) | (0b000 << 12) | (rd << 7) | JALR_OPCODE

    elif mnemonic == 'SW':
        rs1 = args['rs1'] & 0x1F
        rs2 = args['rs2'] & 0x1F
        imm = _mask(args['imm'], 12)
        imm_upper = (imm >> 5) & 0x7F
        imm_lower = imm & 0x1F
        return (imm_upper << 25) | (rs2 << 20) | (rs1 << 15) | (0b010 << 12) | (imm_lower << 7) | STORE_OPCODE

    elif mnemonic in B_FUNCT3:
        funct3 = B_FUNCT3[mnemonic]
        rs1 = args['rs1'] & 0x1F
        rs2 = args['rs2'] & 0x1F
        imm = _mask(args['imm'], 13)
        bit_12 = (imm >> 12) & 0x1
        bit_11 = (imm >> 11) & 0x1
        bits_10_5 = (imm >> 5) & 0x3F
        bits_4_1 = (imm >> 1) & 0xF
        return (bit_12 << 31) | (bits_10_5 << 25) | (rs2 << 20) | (rs1 << 15) | (funct3 << 12) | (bits_4_1 << 8) | (bit_11 << 7) | BRANCH_OPCODE

    elif mnemonic == 'LUI':
        rd = args['rd'] & 0x1F
        imm = _mask(args['imm'], 20)
        return (imm << 12) | (rd << 7) | LUI_OPCODE

    elif mnemonic == 'AUIPC':
        rd = args['rd'] & 0x1F
        imm = _mask(args['imm'], 20)
        return (imm << 12) | (rd << 7) | AUIPC_OPCODE

    elif mnemonic == 'JAL':
        rd = args['rd'] & 0x1F
        imm = _mask(args['imm'], 21)
        bit_20 = (imm >> 20) & 0x1
        bits_10_1 = (imm >> 1) & 0x3FF
        bit_11 = (imm >> 11) & 0x1
        bits_19_12 = (imm >> 12) & 0xFF
        return (bit_20 << 31) | (bits_10_1 << 21) | (bit_11 << 20) | (bits_19_12 << 12) | (rd << 7) | JAL_OPCODE

    else:
        raise ValueError(f"Unknown instruction: {mnemonic}")


def decode_instruction(instruction: int) -> Dict[str, Union[str, int]]:
    """Decode a 32-bit RISC-V instruction."""
    opcode = instruction & 0x7F
    rd = (instruction >> 7) & 0x1F
    funct3 = (instruction >> 12) & 0x7
    rs1 = (instruction >> 15) & 0x1F
    rs2 = (instruction >> 20) & 0x1F
    funct7 = (instruction >> 25) & 0x7F

    if opcode == R_TYPE_OPCODE:
        for name, (f7, f3) in R_FUNCT.items():
            if funct7 == f7 and funct3 == f3:
                return {'mnemonic': name, 'format': 'R', 'rd': rd, 'rs1': rs1, 'rs2': rs2}
        return {'mnemonic': 'UNKNOWN_R', 'format': 'R', 'rd': rd, 'rs1': rs1, 'rs2': rs2}

    elif opcode == I_ARITH_OPCODE:
        imm = _sign_extend((instruction >> 20) & 0xFFF, 12)
        for name, f3 in I_FUNCT3.items():
            if funct3 == f3:
                return {'mnemonic': name, 'format': 'I', 'rd': rd, 'rs1': rs1, 'imm': imm}
        return {'mnemonic': 'UNKNOWN_I', 'format': 'I', 'rd': rd, 'rs1': rs1, 'imm': imm}

    elif opcode == LOAD_OPCODE:
        imm = _sign_extend((instruction >> 20) & 0xFFF, 12)
        return {'mnemonic': 'LW', 'format': 'I', 'rd': rd, 'rs1': rs1, 'imm': imm}

    elif opcode == JALR_OPCODE:
        imm = _sign_extend((instruction >> 20) & 0xFFF, 12)
        return {'mnemonic': 'JALR', 'format': 'I', 'rd': rd, 'rs1': rs1, 'imm': imm}

    elif opcode == STORE_OPCODE:
        imm_low = (instruction >> 7) & 0x1F
        imm_high = (instruction >> 25) & 0x7F
        imm = _sign_extend((imm_high << 5) | imm_low, 12)
        return {'mnemonic': 'SW', 'format': 'S', 'rs1': rs1, 'rs2': rs2, 'imm': imm}

    elif opcode == BRANCH_OPCODE:
        bit_12 = (instruction >> 31) & 0x1
        bit_11 = (instruction >> 7) & 0x1
        bits_10_5 = (instruction >> 25) & 0x3F
        bits_4_1 = (instruction >> 8) & 0xF
        imm = (bit_12 << 12) | (bit_11 << 11) | (bits_10_5 << 5) | (bits_4_1 << 1)
        imm = _sign_extend(imm, 13)
        for name, f3 in B_FUNCT3.items():
            if funct3 == f3:
                return {'mnemonic': name, 'format': 'B', 'rs1': rs1, 'rs2': rs2, 'imm': imm}
        return {'mnemonic': 'UNKNOWN_B', 'format': 'B', 'rs1': rs1, 'rs2': rs2, 'imm': imm}

    elif opcode == LUI_OPCODE:
        imm = (instruction >> 12) & 0xFFFFF
        return {'mnemonic': 'LUI', 'format': 'U', 'rd': rd, 'imm': imm}

    elif opcode == AUIPC_OPCODE:
        imm = (instruction >> 12) & 0xFFFFF
        return {'mnemonic': 'AUIPC', 'format': 'U', 'rd': rd, 'imm': imm}

    elif opcode == JAL_OPCODE:
        bit_20 = (instruction >> 31) & 0x1
        bits_10_1 = (instruction >> 21) & 0x3FF
        bit_11 = (instruction >> 20) & 0x1
        bits_19_12 = (instruction >> 12) & 0xFF
        imm = (bit_20 << 20) | (bits_19_12 << 12) | (bit_11 << 11) | (bits_10_1 << 1)
        imm = _sign_extend(imm, 21)
        return {'mnemonic': 'JAL', 'format': 'J', 'rd': rd, 'imm': imm}

    else:
        raise ValueError(f"Unknown opcode: 0b{opcode:07b}")

