from typing import List, Dict, Set


CALLER_SAVED = {'ra', 't0', 't1', 't2', 't3', 't4', 't5', 't6',
                'a0', 'a1', 'a2', 'a3', 'a4', 'a5', 'a6', 'a7'}
CALLEE_SAVED = {'sp', 's0', 's1', 's2', 's3', 's4', 's5', 's6',
                's7', 's8', 's9', 's10', 's11'}
FIXED = {'zero', 'gp', 'tp'}


class CallingConventionVerifier:
    """Verifies RISC-V calling convention compliance."""

    def __init__(self):
        self.caller_saved: Set[str] = CALLER_SAVED.copy()
        self.callee_saved: Set[str] = CALLEE_SAVED.copy()
        self.fixed: Set[str] = FIXED.copy()

    def simulate_call(
        self, caller_saved_regs: List[str], callee_func: str
    ) -> Dict:
        saved_by_caller = set(caller_saved_regs)
        must_preserve = self.callee_saved.copy()
        all_regs = self.caller_saved | self.callee_saved | self.fixed
        free_for_callee = self.caller_saved - saved_by_caller
        free_for_callee |= {'t0', 't1', 't2', 't3', 't4', 't5', 't6'} & self.caller_saved

        return {
            'saved_by_caller': sorted(saved_by_caller),
            'must_be_preserved_by_callee': sorted(must_preserve),
            'free_for_callee': sorted(self.caller_saved),
        }

    def verify_prologue(
        self, saved_regs: List[str], frame_size: int
    ) -> Dict:
        errors: List[str] = []

        if frame_size % 16 != 0:
            errors.append(
                f"Frame size {frame_size} is not 16-byte aligned"
            )

        valid_to_save = self.callee_saved | {'ra'}
        for reg in saved_regs:
            if reg not in valid_to_save:
                errors.append(
                    f"Register '{reg}' is not callee-saved or ra — saving it in prologue is unusual"
                )

        needed_bytes = len(saved_regs) * 4
        if frame_size < needed_bytes:
            errors.append(
                f"Frame size {frame_size} too small for {len(saved_regs)} registers ({needed_bytes} bytes needed)"
            )

        return {
            'valid': len(errors) == 0,
            'errors': errors,
            'stack_usage': {
                'frame_size': frame_size,
                'saved_registers': len(saved_regs),
                'register_bytes': needed_bytes,
                'remaining_for_locals': max(0, frame_size - needed_bytes),
            },
        }

    def verify_epilogue(
        self,
        saved_in_prologue: List[str],
        restored_regs: List[str],
        frame_size_alloc: int,
        frame_size_dealloc: int,
    ) -> Dict:
        errors: List[str] = []
        saved_set = set(saved_in_prologue)
        restored_set = set(restored_regs)

        missing = saved_set - restored_set
        extra = restored_set - saved_set

        if missing:
            errors.append(
                f"Registers saved but not restored: {sorted(missing)}"
            )
        if extra:
            errors.append(
                f"Registers restored but not saved: {sorted(extra)}"
            )
        if frame_size_alloc != frame_size_dealloc:
            errors.append(
                f"Frame size mismatch: allocated {frame_size_alloc}, deallocated {frame_size_dealloc}"
            )

        return {
            'valid': len(errors) == 0,
            'errors': errors,
            'missing_restores': sorted(missing),
        }

    def analyze_register_usage(
        self, used_regs: List[str], makes_calls: bool
    ) -> Dict:
        must_save: List[str] = []
        reasons: Dict[str, str] = {}

        for reg in used_regs:
            if reg in self.callee_saved and reg != 'sp':
                must_save.append(reg)
                reasons[reg] = f"Callee-saved register used — must save/restore to preserve caller's value"

        if makes_calls and 'ra' not in must_save:
            must_save.append('ra')
            reasons['ra'] = "Function makes calls — ra will be overwritten by JAL, must save/restore"

        return {
            'must_save': sorted(must_save),
            'reason': reasons,
        }
